import { useStatusAnimation } from './use-status-animation';

/**
 * Formats a status string to title case for display.
 */
function formatStatusLabel(status: string): string {
  return status
    .replace(/[_-]/g, ' ')
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

