/**
 * StatusBadge component for displaying status indicators.
 *
 * @example
 * ```tsx
 * // Basic usage with automatic lookup
 * <StatusBadge status="active" />
 *
 * // With custom label
 * <StatusBadge status="processing" label="In Progress" />
 *
 * // Badge variant with animation
 * <StatusBadge
 *   status="indexing"
 *   variant="badge"
 *   animation="pulse"
 * />
 *
 * // Custom category override
 * <StatusBadge
 *   status="custom-status"
 *   category="success"
 *   label="Custom Label"
 * />
 * ```
 */
const StatusBadge = forwardRef<HTMLDivElement, StatusBadgeProps>(
  (
    {
      status,
      label,
      category,
      variant = 'dot',
      size = 'default',
      animation = 'none',
      showDot = true,
      icon,
      disableAnimation = false,
      className,
      ...props
    },
    ref
  ) => {
    // Look up status in registry
    const config = getStatusConfig(status);

    // Resolve final values (props override registry)
    const resolvedCategory: StatusCategory =
      category ?? config?.category ?? 'neutral';
    const resolvedLabel = label ?? config?.label ?? formatStatusLabel(status);
    const resolvedAnimation: StatusAnimation =
      animation !== 'none' ? animation : (config?.animation ?? 'none');

    // Get animation classes
    const { containerClasses, dotClasses, isAnimated } = useStatusAnimation({
      animation: resolvedAnimation,
      disableAnimation,
    });

    // Determine if we should show the dot
    const shouldShowDot = variant === 'dot' && showDot && !icon;

    return (
      <div
        ref={ref}
        data-slot="status-badge"
        data-status={status}
        data-category={resolvedCategory}
        data-animated={isAnimated || undefined}
        className={cn(
          statusBadgeVariants({ variant, category: resolvedCategory, size }),
          containerClasses,
          className
        )}
        {...props}
      >
        {/* Icon or Dot */}
        {icon ? (
          <span className="shrink-0">{icon}</span>
        ) : shouldShowDot ? (
          <span
            data-slot="status-dot"
            className={cn(
              statusDotVariants({ category: resolvedCategory, size }),
              dotClasses
            )}
          />
        ) : null}

        {/* Label */}
        <span data-slot="status-label">{resolvedLabel}</span>
      </div>
    );
  }
);

StatusBadge.displayName = 'StatusBadge';

export { StatusBadge };
