// Initialize registry with core statuses
Object.entries(CORE_STATUSES).forEach(([key, config]) => {
  STATUS_REGISTRY.set(key.toLowerCase(), config);
});

/**
 * Look up a status in the registry.
 * Returns undefined if not found.
 */
export function getStatusConfig(status: string): StatusConfig | undefined {
  return STATUS_REGISTRY.get(status.trim().toLowerCase());
}

/**
 * Register a new status or override an existing one.
 *
 * @example
 * ```ts
 * registerStatus('put-away pending', {
 *   category: 'warning',
 *   label: 'Put-Away Pending'
 * });
 * ```
 */
export function registerStatus(key: string, config: StatusConfig): void {
  STATUS_REGISTRY.set(key.toLowerCase(), config);
}

/**
 * Register multiple statuses at once.
 *
 * @example
 * ```ts
 * registerStatuses({
 *   'await eta': { category: 'success', label: 'Await ETA' },
 *   'eta pending': { category: 'warning', label: 'ETA Pending' },
 * });
 * ```
 */
export function registerStatuses(
  statuses: Record<string, StatusConfig>
): void {
  Object.entries(statuses).forEach(([key, config]) => {
    registerStatus(key, config);
  });
}

/**
 * Check if a status is registered.
 */
export function isStatusRegistered(status: string): boolean {
  return STATUS_REGISTRY.has(status.trim().toLowerCase());
}

/**
 * Get all registered statuses (for debugging/documentation).
 */
export function getAllStatuses(): Map<string, StatusConfig> {
  return new Map(STATUS_REGISTRY);
}

/**
 * Clear custom registrations (useful for testing).
 * Resets to core statuses only.
 */
export function resetRegistry(): void {
  STATUS_REGISTRY.clear();
  Object.entries(CORE_STATUSES).forEach(([key, config]) => {
    STATUS_REGISTRY.set(key.toLowerCase(), config);
  });
}
