'use client';

import { useReducedMotion } from '../../../motion';
import type { StatusAnimation } from './types';

interface UseStatusAnimationOptions {
  animation: StatusAnimation;
  disableAnimation?: boolean;
}

interface UseStatusAnimationReturn {
  /** Classes to apply to the badge container */
  containerClasses: string;
  /** Classes to apply to the dot element */
  dotClasses: string;
  /** Whether animation is currently active */
  isAnimated: boolean;
}

/**
 * Hook to get animation classes for StatusBadge.
 * Respects user's reduced motion preference.
 */
export function useStatusAnimation({
  animation,
  disableAnimation = false,
}: UseStatusAnimationOptions): UseStatusAnimationReturn {
  const prefersReducedMotion = useReducedMotion();

  // No animation if disabled or user prefers reduced motion
  const isAnimated =
    animation !== 'none' && !disableAnimation && !prefersReducedMotion;

  if (!isAnimated) {
    return {
      containerClasses: '',
      dotClasses: '',
      isAnimated: false,
    };
  }

  switch (animation) {
    case 'pulse':
      return {
        containerClasses: '',
        dotClasses: 'animate-status-dot-pulse',
        isAnimated: true,
      };
    case 'pop':
      return {
        containerClasses: 'animate-status-pop',
        dotClasses: '',
        isAnimated: true,
      };
    case 'shake':
      return {
        containerClasses: 'animate-status-shake',
        dotClasses: '',
        isAnimated: true,
      };
    default:
      return {
        containerClasses: '',
        dotClasses: '',
        isAnimated: false,
      };
  }
}
